Use ASP.NET Core's **`WebApplicationFactory<T>`** — it hosts your app in-memory and gives you an `HttpClient` that talks to it without opening a real port.

Here's the pattern:

**1. Add the test package**
```bash
dotnet add tests/MyMcp.Tests.csproj package Microsoft.AspNetCore.Mvc.Testing
```

**2. Write a test fixture**
```csharp
using Microsoft.AspNetCore.Mvc.Testing;

public class McpIntegrationTests : IClassFixture<WebApplicationFactory<Program>>
{
    private readonly HttpClient _client;

    public McpIntegrationTests(WebApplicationFactory<Program> factory)
    {
        _client = factory.CreateClient();
    }

    [Fact]
    public async Task Initialize_ReturnsServerCapabilities()
    {
        var request = new
        {
            jsonrpc = "2.0",
            id = 1,
            method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test-client", version = "1.0" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.Equal("2025-03-26",
            body.GetProperty("result")
                .GetProperty("protocolVersion")
                .GetString());
    }

    [Fact]
    public async Task ToolsList_ReturnsRegisteredTools()
    {
        // Initialize first (stateful session via Mcp-Session-Id header)
        var init = await InitializeSession();
        var sessionId = init.Headers.GetValues("Mcp-Session-Id").First();

        var request = new { jsonrpc = "2.0", id = 2, method = "tools/list" };
        var msg = new HttpRequestMessage(HttpMethod.Post, "/mcp")
        {
            Content = JsonContent.Create(request)
        };
        msg.Headers.Add("Mcp-Session-Id", sessionId);

        var response = await _client.SendAsync(msg);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        var tools = body.GetProperty("result").GetProperty("tools");
        Assert.True(tools.GetArrayLength() > 0);
    }

    private async Task<HttpResponseMessage> InitializeSession()
    {
        var request = new
        {
            jsonrpc = "2.0", id = 1, method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test", version = "1.0" }
            }
        };
        return await _client.PostAsJsonAsync("/mcp", request);
    }
}
```

**3. Expose `Program` for the factory** — in your server project, add:
```csharp
// At the bottom of Program.cs (or a separate file)
public partial class Program { }
```

**Key points:**

- **No real port** — `WebApplicationFactory` uses an in-memory `TestServer` under the hood.
- **Full pipeline** — middleware, routing, DI, and your MCP handler all run exactly as in production.
- **Session tracking** — if your server uses `Mcp-Session-Id`, capture it from the `initialize` response and send it on subsequent requests.
- **SSE streams** — for streaming responses, read with `GetStreamAsync` and parse `text/event-stream` lines incrementally.
- **Override services** — use `factory.WithWebHostBuilder(b => b.ConfigureServices(...))` to swap in test doubles (e.g., a fake database).
